/-!
# Voting Theory for Peer Review Aggregation

This module formalizes the Borda count optimality theorem
for aggregating judge rankings in decentralized peer review.
-/

namespace VotingTheory

/-- A paper is identified by its index -/
def Paper := ℕ

/-- A judge's ranking is a total order on papers -/
structure JudgeRanking where
  papers : Finset Paper
  order : Paper → Paper → Prop
  h_total : ∀ a b, a ∈ papers → b ∈ papers → order a b ∨ order b a
  h_trans : ∀ a b c, order a b → order b c → order a c
  h_antisymm : ∀ a b, order a b → order b a → a = b

/-- Borda score of a paper -/
def bordaScore (rankings : List JudgeRanking) (p : Paper) : ℕ :=
  (rankings.map (fun r =>
    (r.papers.filter (fun q => r.order p q)).card
  )).sum

/-- Kendall tau distance between two rankings -/
def kendallTau (r1 r2 : JudgeRanking) : ℕ :=
  let pairs := r1.pairs -- all unordered pairs
  (pairs.filter (fun (a, b) =>
    (r1.order a b ∧ r2.order b a) ∨ (r1.order b a ∧ r2.order a b)
  )).card

/-- Theorem: Borda count minimizes average Kendall tau distance -/
theorem borda_minimizes_kendall_tau
    (rankings : List JudgeRanking)
    (h_nonempty : rankings ≠ [])
    (h_consistent : ∀ r ∈ rankings, r.papers = (rankings.head!).papers) :
    let bordaRanking := sortByBorda rankings
    ∀ otherRanking : JudgeRanking,
      (∑ r in rankings, kendallTau bordaRanking r) ≤
      (∑ r in rankings, kendallTau otherRanking r) := by
  unfold bordaScore kendallTau
  -- Key insight: Borda score counts pairwise victories
  -- Kendall tau counts pairwise disagreements
  -- Minimizing disagreements = maximizing agreements = Borda
  sorry -- Requires detailed combinatorial argument

/-- Theorem: Borda score equals pairwise victory count -/
theorem borda_equals_pairwise_victories
    (rankings : List JudgeRanking)
    (p : Paper)
    (h_p : p ∈ (rankings.head!).papers) :
    bordaScore rankings p =
      ∑ q in (rankings.head!).papers,
        if q ≠ p then
          (rankings.filter (fun r => r.order p q)).card
        else 0 := by
  unfold bordaScore
  -- Each paper's Borda score is the count of papers it beats
  -- Sum over rankings = sum over pairwise victories
