// Voting methods for peer review aggregation
function mulberry32(seed) {
  return function() {
    let t = seed += 0x6D2B79F5;
    t = Math.imul(t ^ t >>> 15, t | 1);
    t ^= t + Math.imul(t ^ t >>> 7, t | 61);
    return ((t ^ t >>> 14) >>> 0) / 4294967296;
  };
}

// Borda Count
function bordaCount(rankings) {
  const n = rankings[0].length;
  const scores = new Array(n).fill(0);
  for (const ranking of rankings) {
    for (let i = 0; i < n; i++) {
      scores[ranking[i]] += n - 1 - i;
    }
  }
  return scores.map((s, i) => ({paper: i, score: s}))
    .sort((a, b) => b.score - a.score);
}

// Kemeny-Young (exact for small n, brute force)
function kemenyYoung(rankings) {
  const n = rankings[0].length;
  // Compute pairwise preference matrix
  const pairwise = Array.from({length: n}, () => new Array(n).fill(0));
  for (const ranking of rankings) {
    for (let i = 0; i < n; i++) {
      for (let j = i + 1; j < n; j++) {
        pairwise[ranking[i]][ranking[j]]++;
        pairwise[ranking[j]][ranking[i]]--;
      }
    }
  }
  // For small n, try all permutations
  if (n <= 8) {
    let bestScore = -Infinity, bestOrder = null;
    const perms = getPermutations(Array.from({length: n}, (_, i) => i));
    for (const perm of perms) {
      let score = 0;
      for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
          score += pairwise[perm[i]][perm[j]];
        }
      }
      if (score > bestScore) { bestScore = score; bestOrder = perm; }
    }
    return bestOrder.map((p, i) => ({paper: p, score: bestScore}));
  }
  // For larger n, use greedy approximation
  return greedyKemeny(pairwise, n);
}

function greedyKemeny(pairwise, n) {
  const order = [];
  const remaining = new Set(Array.from({length: n}, (_, i) => i));
  while (remaining.size > 0) {
    let bestPaper = -1, bestScore = -Infinity;
    for (const p of remaining) {
      let score = 0;
      for (const q of order) score += pairwise[p][q];
      for (const q of remaining) {
        if (q !== p) score += pairwise[p][q] * 0.5;
      }
      if (score > bestScore) { bestScore = score; bestPaper = p; }
    }
    order.push(bestPaper);
    remaining.delete(bestPaper);
  }
  return order.map((p, i) => ({paper: p, score: i}));
}

function getPermutations(arr) {
  if (arr.length <= 1) return [arr];
  const result = [];
  for (let i = 0; i < arr.length; i++) {
    const rest = [...arr.slice(0, i), ...arr.slice(i + 1)];
    for (const perm of getPermutations(rest)) {
      result.push([arr[i], ...perm]);
    }
  }
  return result;
}

// Copeland Method
function copeland(rankings) {
  const n = rankings[0].length;
  const wins = new Array(n).fill(0);
  const losses = new Array(n).fill(0);
  for (let i = 0; i < n; i++) {
    for (let j = i + 1; j < n; j++) {
      let iWins = 0, jWins = 0;
      for (const r of rankings) {
        if (r.indexOf(i) < r.indexOf(j)) iWins++;
        else jWins++;
      }
      if (iWins > jWins) { wins[i]++; losses[j]++; }
      else if (jWins > iWins) { wins[j]++; losses[i]++; }
    }
  }
  return Array.from({length: n}, (_, i) => ({
    paper: i, score: wins[i] - losses[i]
  })).sort((a, b) => b.score - a.score);
}

// Run comparison
function runComparison(numPapers, numJudges, seed) {
  const rng = mulberry32(seed);
  // Generate random judge rankings
  const rankings = [];
  for (let j = 0; j < numJudges; j++) {
    const ranking = Array.from({length: numPapers}, (_, i) => i);
    // Fisher-Yates shuffle with bias
    for (let i = ranking.length - 1; i > 0; i--) {
      const swapIdx = Math.floor(rng() * (i + 1));
      [ranking[i], ranking[swapIdx]] = [ranking[swapIdx], ranking[i]];
    }
    rankings.push(ranking);
  }

  const borda = bordaCount(rankings);
  const kemeny = kemenyYoung(rankings);
  const copelandResult = copeland(rankings);

  return {
    numPapers,
    numJudges,
    bordaWinner: borda[0].paper,
    kemenyWinner: kemeny[0].paper,
    copelandWinner: copelandResult[0].paper,
    bordaKemenyAgree: borda[0].paper === kemeny[0].paper,
    bordaTop3: borda.slice(0, 3).map(x => x.paper),
    kemenyTop3: kemeny.slice(0, 3).map(x => x.paper)
  };
}

// Run 100 trials
const results = [];
for (let trial = 0; trial < 100; trial++) {
  results.push(runComparison(6, 7, 42 + trial));
}
const agreementRate = results.filter(r => r.bordaKemenyAgree).length / results.length;
JSON.stringify({trials: 100, agreementRate: agreementRate.toFixed(3)}, null, 2);
